INSERT INTO bluenote_order.user_coupon (
    user_coupon_id, user_id, template_id, activity_id, source_order_id, coupon_status,
    face_value, threshold_amount, valid_start_at, valid_end_at, issued_at,
    used_at, expired_at, created_at, updated_at
) VALUES (
    #{userCouponId}, #{userId}, #{templateId}, #{activityId}, #{sourceOrderId}, #{couponStatus},
    #{faceValue}, #{thresholdAmount}, #{validStartAt}, #{validEndAt}, #{issuedAt},
    #{usedAt}, #{expiredAt}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT uc.*, ct.template_name, ca.activity_name
FROM bluenote_order.user_coupon uc
JOIN bluenote_order.coupon_template ct ON ct.template_id = uc.template_id
JOIN bluenote_order.coupon_activity ca ON ca.activity_id = uc.activity_id
WHERE uc.user_id = #{userId}

  AND uc.coupon_status = #{status}


  AND (uc.issued_at < #{cursorIssuedAt}
       OR (uc.issued_at = #{cursorIssuedAt} AND uc.user_coupon_id < #{cursorId}))

ORDER BY uc.issued_at DESC, uc.user_coupon_id DESC
LIMIT #{limit}

